#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char ch; scanf(" %c", &ch);
        switch(ch){
            case 'a': case 'e': case 'i': case 'o': case 'u':
                printf("Vowel\n");
                break;
            default:
                printf("Consonant\n");
        }
    }
    return 0;
}

