import sys

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
out = []
for i in range(1, T+1):
    ch = data[i]
    if ch in ('a', 'e', 'i', 'o', 'u'):
        out.append('Vowel')
    else:
        out.append('Consonant')
print('\n'.join(out))

